import React from 'react';
import PageLogo from '../Logo/GnuLinuxLogo.svg';
import HeaderInfoBackgroundImage from '../Background/HeaderTitleInfoBackgroundImage.jpg';
import './HeaderDomainInfo.css';

const HeaderDomainInfo = ({
  domainLogo = PageLogo,
  domainURL = "www.unix69.githubio.com",
  pageName = "Unix69",
  className = "header-title-info",
  domainLogoClass = "header-title-info-domain-logo",
  domainUrlClass = "header-title-info-domain-url"
}) => {
  return (
    <div className={className} style={{ backgroundImage: `url(${HeaderInfoBackgroundImage})` }}>
      <img src={domainLogo} alt="Domain Logo" className={domainLogoClass}/>
      <a href={domainURL} className={domainUrlClass}>{pageName}</a>
    </div>
  );
};

export default HeaderDomainInfo;
